    @PostMapping("/products")
    public ResponseEntity<String> indexProduct(@RequestBody Map<String, Object> product) throws IOException {
        IndexRequest request = new IndexRequest("products");
        request.source(product, XContentType.JSON);

        BulkRequest bulkRequest = new BulkRequest();
        bulkRequest.add(request);

        BulkResponse bulkResponse = client.bulk(bulkRequest, RequestOptions.DEFAULT);
        if (bulkResponse.hasFailures()) {
            return ResponseEntity.status(500).body("Failed to index product");
        }
        return ResponseEntity.ok("Product indexed successfully");
    }

